const input = $input.first().json;

// AI Agent (LangChain toolWorkflow) truyen input duoi nhieu dang:
//  1. { user_message: "...", chat_id: 123 }
//  2. { params: { user_message, chat_id } } (wrapper tu agent node)
//  3. { text: "..." } (fallback Telegram text field)
//  4. { message: "..."" } (một số tool agent dùng)
//  5. { query: "..." } (RAG-style tool input / LangChain DynamicTool schema transform)
//  6. { query: "<JSON string>" } (khi LLM goi tool voi object khong match schema, n8n wrap input.json={} nhung query co the chua JSON)
//  7. { input: "..." } (LangChain Tool.call wrap)
//  8. "<plain string>" (truong hop cuc bien)
//  9. {} (empty - khi agent goi nham tool hoac args khong match DynamicTool schema)
//
// Muc tieu: parse duoc nhieu nhat, fallback an toan (khong throw).
const candidates = [input, input.params || {}, input.input || {}, input.data || {}];
let userMessage = '';
let chatId = '';

const isPlausibleText = (s) => typeof s === 'string' && s.trim().length > 0;

for (const obj of candidates) {
  if (!obj || typeof obj !== 'object') continue;

  // Parse query: neu la JSON string chua cac field quen thuoc (user_message, input, chat_id)
  if (isPlausibleText(obj.query)) {
    try {
      const parsed = JSON.parse(obj.query);
      if (parsed && typeof parsed === 'object') {
        userMessage = userMessage
          || parsed.user_message
          || parsed.input
          || parsed.text
          || parsed.message
          || parsed.content
          || '';
        chatId = chatId
          || parsed.chat_id
          || parsed.chatId
          || '';
        continue; // da parse thanh object, khong fallback sang raw string
      }
    } catch (e) {
      // khong phai JSON string, fallback xu ly nhu text thuong
    }
  }

  userMessage = userMessage
    || obj.user_message
    || obj.text
    || obj.message
    || obj.query
    || obj.content
    || obj.input
    || '';
  chatId = chatId
    || obj.chat_id
    || obj.chatId
    || obj.chat_id_str
    || '';
}

// Fallback neu toan bo input la string
if (!userMessage && typeof input === 'string') {
  userMessage = input;
}

// Fallback neu AI Agent truyen string trong field khac
if (!userMessage && input.json && typeof input.json === 'string') {
  userMessage = input.json;
}

const trimmed = String(userMessage || '').trim();
const isEmpty = trimmed.length === 0;

// Defense-in-depth: khi AI Agent LangChain tool goi sub-workflow chi voi field `query`
// (khong co chat_id o bat ky candidate nao), fallback ve env admin de van co the
// reply Telegram cho admin. Workflow nay chi danh cho admin (1 chat_id).
const envChatId = String($env.ADMIN_TELEGRAM_CHAT_ID || '').trim();
if (!chatId && envChatId) {
  chatId = envChatId;
}

return [{
  json: {
    user_message: trimmed,
    chat_id: String(chatId || ''),
    session_id: input.session_id || (input.params && input.params.session_id) || '',
    is_empty_input: isEmpty,
  }
}];

