const input = $input.first().json;
const extract = $('Extract Input').first().json;
let intentData;
try {
  const text = input.candidates[0].content.parts[0].text;
  intentData = JSON.parse(text);
} catch (e) {
  // Fallback: default READ nếu parse lỗi
  intentData = { action: 'READ', filter: null, sheet_name: 'Nhật ký hóa đơn' };
}

const action = (intentData.action || 'READ').toUpperCase();
const validActions = ['READ', 'WRITE'];
const finalAction = validActions.includes(action) ? action : 'READ';

return [{
  json: {
    user_message: extract.user_message,
    chat_id: extract.chat_id,
    action: finalAction,
    filter: intentData.filter || null,
    sheet_name: intentData.sheet_name || 'Nhật ký hóa đơn',
    raw_intent: intentData,
  }
}];

const rows = $input.all().map(i => i.json);
const intentData = $('Parse Intent + Guards').first().json;

let filterVal = String(intentData.filter || '').trim().toLowerCase();
filterVal = filterVal
  .replace(/^(ma\s+|khach\s+|sdt\s+|so\s+)/g, '')
  .trim();

if (!filterVal || filterVal.length < 2) {
  const last50 = rows.slice(-50);
  return [{
    json: {
      rows: last50,
      filter: filterVal,
      has_filter: false
    }
  }];
}

const filtered = rows.filter(r => {
  for (const key in r) {
    if (Object.prototype.hasOwnProperty.call(r, key) && r[key]) {
      const valStr = String(r[key]).toLowerCase();
      if (valStr.includes(filterVal)) {
        return true;
      }
    }
  }
  return false;
});

const result = filtered.slice(0, 50);
return [{
  json: {
    rows: result,
    filter: filterVal,
    has_filter: true
  }
}];

