const input = $input.first().json;
const extract = $('Parse Intent + Guards').first().json;

let rowData;
try {
  const text = input.candidates[0].content.parts[0].text;
  rowData = JSON.parse(text);
} catch (e) {
  return [{
    json: {
      valid: false,
      missing: ['ALL'],
      error: 'Gemini trả về JSON không hợp lệ. Vui lòng thử diễn đạt lại.',
      chat_id: extract.chat_id,
    }
  }];
}

const required = ['so_hoa_don', 'ma_san_pham', 'ten_khach', 'sdt_khach', 'ngay_thue', 'ngay_tra'];
const missing = required.filter(k => !rowData[k] || String(rowData[k]).trim() === '');

// Validate SĐT format (10 số, bắt đầu 0)
if (rowData.sdt_khach && !/^0\d{9}$/.test(String(rowData.sdt_khach).replace(/\D/g, ''))) {
  const sdtClean = String(rowData.sdt_khach).replace(/\D/g, '');
  if (sdtClean.length === 10 && sdtClean.startsWith('0')) {
    rowData.sdt_khach = sdtClean;  // Auto-fix
  } else {
    missing.push('sdt_khach (không hợp lệ, cần 10 số bắt đầu 0)');
  }
}

// Validate date format dd/MM/yyyy
const dateRegex = /^\d{2}\/\d{2}\/\d{4}$/;
if (rowData.ngay_thue && !dateRegex.test(rowData.ngay_thue)) {
  missing.push('ngay_thue (không đúng định dạng dd/MM/yyyy)');
}
if (rowData.ngay_tra && !dateRegex.test(rowData.ngay_tra)) {
  missing.push('ngay_tra (không đúng định dạng dd/MM/yyyy)');
}

if (missing.length > 0) {
  return [{
    json: {
      valid: false,
      missing: missing,
      data: rowData,
      chat_id: extract.chat_id,
      error: 'Thiếu hoặc sai định dạng: ' + missing.join(', '),
    }
  }];
}

return [{
  json: {
    valid: true,
    data: rowData,
    chat_id: extract.chat_id,
  }
}];

const input = $input.first().json;
const data = input.data || {};
// Map Gemini output -> column header in sheet
// Header: STT, Số hóa đơn, Mã Sản phẩm, Tên khách, SĐT khách, Địa chỉ, Ngày thuê, Ngày trả, Nhân viên, Hoa hồng, E mail của KH
return [{
  json: {
    // STT sẽ được tự sinh bằng công thức ROW()-1
    so_hoa_don: data.so_hoa_don || '',
    ma_san_pham: data.ma_san_pham || '',
    ten_khach: data.ten_khach || '',
    sdt_khach: data.sdt_khach || '',
    dia_chi: data.dia_chi || '',
    ngay_thue: data.ngay_thue || '',
    ngay_tra: data.ngay_tra || '',
    nhan_vien: data.nhan_vien || '',
    hoa_hong: data.hoa_hong || '',
    email_kh: data.email_kh || '',
    chat_id: input.chat_id,
  }
}];

const extract = $('Parse Intent + Guards').first().json;
const validate = $('Validate Required Fields').first().json;
let text = '';

// Defense-in-depth: fallback ADMIN_TELEGRAM_CHAT_ID khi Extract Input khong lay duoc chat_id
let chatId = String(extract.chat_id || '').trim();
if (!chatId) {
  chatId = String($env.ADMIN_TELEGRAM_CHAT_ID || '').trim();
}

const success = validate.valid !== false;
if (!success) {
  // Có lỗi validation
  const missing = validate.missing || [];
  text = '⚠️ *Không thể thêm đơn - thiếu thông tin:*\n\n';
  text += 'Thiếu/sai: ' + missing.join(', ') + '\n\n';
  text += 'Các trường bắt buộc:\n';
  text += '• Số hóa đơn\n';
  text += '• Mã Sản phẩm (VDxx)\n';
  text += '• Tên khách\n';
  text += '• SĐT khách (10 số, bắt đầu 0)\n';
  text += '• Ngày thuê (dd/MM/yyyy)\n';
  text += '• Ngày trả (dd/MM/yyyy)\n';
  text += '\n📝 Ví dụ: "Thêm đơn: HĐ 999, SP VD28, khách LÊ VĂN E, SĐT 0912345678, thuê 20/06/2026 trả 25/06/2026"';
} else {
  // Thành công - preview row vừa ghi
  const d = validate.data;
  text = '✅ *Đã thêm đơn hàng mới thành công!*\n\n';
  text += '📋 *Số hóa đơn:* ' + (d.so_hoa_don || '(trống)') + '\n';
  text += '👗 *Mã SP:* ' + (d.ma_san_pham || '(trống)') + '\n';
  text += '👤 *Khách:* ' + (d.ten_khach || '(trống)') + '\n';
  text += '📱 *SĐT:* ' + (d.sdt_khach || '(trống)') + '\n';
  if (d.dia_chi) text += '📍 *Địa chỉ:* ' + d.dia_chi + '\n';
  text += '📅 *Thuê:* ' + (d.ngay_thue || '(trống)') + ' → *Trả:* ' + (d.ngay_tra || '(trống)') + '\n';
  if (d.nhan_vien) text += '👨‍💼 *Nhân viên:* ' + d.nhan_vien + '\n';
  if (d.hoa_hong) text += '💰 *Hoa hồng:* ' + d.hoa_hong + '\n';
  if (d.email_kh) text += '📧 *Email:* ' + d.email_kh + '\n';
}

return [{ json: { success: success, status: success ? 'success' : 'validation_failed', chat_id: chatId, text: text } }];

const extract = $('Extract Input').first().json;
let chatId = String(extract.chat_id || '').trim();
if (!chatId) {
  chatId = String($env.ADMIN_TELEGRAM_CHAT_ID || '').trim();
}
return [{
  json: {
    success: false,
    status: 'empty_input',
    chat_id: chatId,
    text: '👋 Vui lòng gửi câu hỏi hoặc yêu cầu về Nhật ký hóa đơn.\n\nVí dụ:\n• "Cho tôi xem tất cả đơn của khách NGUYỄN THỊ A"\n• "Thêm đơn: HĐ 999, SP VD28, khách LÊ VĂN E, SĐT 0912345678, thuê 20/06/2026 trả 25/06/2026"'
  }
}];
